            _$glsl$_: "#ifdef GL_ES\nprecision highp float;\n#endif\nvarying vec2 vTex;\nuniform sampler2D samplerFront;\nuniform float uDistance;\nuniform float uAngle;\nuniform float uOpacity;\nuniform float uHue;\nuniform float uSaturation;\nuniform float uBrightness;\nuniform float uBlurRadius;\nvec3 rgb2hsv(vec3 c);\nvec3 hsv2rgb(vec3 c);\nvoid main(void) {\nfloat angleRad = uAngle * 3.14159265 / 180.0;\nvec2 offset = uDistance * 0.001 * vec2(cos(angleRad), sin(angleRad));\nvec4 shadow = vec4(0.0);\nfor(int i = -4; i <= 4; i++) {\nfor(int j = -4; j <= 4; j++) {\nvec2 sampledCoord = vTex + offset + vec2(i, j) * (uBlurRadius * 0.01) * 0.001;\nshadow += texture2D(samplerFront, sampledCoord);\n}\n}\nshadow /= 81.0;\nshadow.a *= uOpacity;\nshadow.rgb = vec3(1.0, 0.0, 0.0);\nvec3 shadowHSV = rgb2hsv(shadow.rgb);\nshadowHSV.x = mod(shadowHSV.x + uHue / 360.0, 1.0); // Normalize hue to [0, 1] range and ensure it wraps around\nshadowHSV.y = uSaturation;\nshadowHSV.z = uBrightness;\nshadow.rgb = hsv2rgb(shadowHSV);\nvec4 col = texture2D(samplerFront, vTex);\nvec4 shadowColor = mix(col, shadow, shadow.a);\ngl_FragColor = mix(shadowColor, col, col.a);\n}\nvec3 rgb2hsv(vec3 c) {\nvec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);\nvec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));\nvec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));\nfloat d = q.x - min(q.w, q.y);\nfloat e = 1.0e-10;\nreturn vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);\n}\nvec3 hsv2rgb(vec3 c) {\nvec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);\nvec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);\nreturn c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);\n}",
            _$glslWebGL2$_: "#version 300 es\nprecision highp float;\nin vec2 vTex;\nout vec4 outColor;\nuniform sampler2D samplerFront;\nuniform float uDistance;\nuniform float uAngle;\nuniform float uOpacity;\nuniform float uHue;\nuniform float uSaturation;\nuniform float uBrightness;\nuniform float uBlurRadius;\nvec3 rgb2hsv(vec3 c);\nvec3 hsv2rgb(vec3 c);\nvoid main(void) {\nfloat angleRad = uAngle * 3.14159265 / 180.0;\nvec2 offset = uDistance * 0.001 * vec2(cos(angleRad), sin(angleRad));\nvec4 shadow = vec4(0.0);\nfor (int i = -4; i <= 4; i++) {\nfor (int j = -4; j <= 4; j++) {\nvec2 sampledCoord = vTex + offset + vec2(float(i), float(j)) * (uBlurRadius * 0.01) * 0.001;\nshadow += texture(samplerFront, sampledCoord);\n}\n}\nshadow /= 81.0;\nshadow.a *= uOpacity;\nshadow.rgb = vec3(1.0, 0.0, 0.0);\nvec3 shadowHSV = rgb2hsv(shadow.rgb);\nshadowHSV.x = mod(shadowHSV.x + uHue / 360.0, 1.0);\nshadowHSV.y = uSaturation;\nshadowHSV.z = uBrightness;\nshadow.rgb = hsv2rgb(shadowHSV);\nvec4 col = texture(samplerFront, vTex);\nvec4 shadowColor = mix(col, shadow, shadow.a);\noutColor = mix(shadowColor, col, col.a);\n}\nvec3 rgb2hsv(vec3 c) {\nvec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);\nvec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));\nvec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));\nfloat d = q.x - min(q.w, q.y);\nfloat e = 1.0e-10;\nreturn vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);\n}\nvec3 hsv2rgb(vec3 c) {\nvec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);\nvec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);\nreturn c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);\n}",
            _$wgsl$_: "%%SAMPLERFRONT_BINDING%% var samplerFront : sampler;\n%%TEXTUREFRONT_BINDING%% var textureFront : texture_2d<f32>;\nstruct ShaderParams {\nuDistance : f32,\nuAngle : f32,\nuOpacity : f32,\nuHue : f32,\nuSaturation : f32,\nuBrightness : f32,\nuBlurRadius : f32\n};\n%%SHADERPARAMS_BINDING%% var<uniform> shaderParams : ShaderParams;\n%%FRAGMENTINPUT_STRUCT%%\n%%FRAGMENTOUTPUT_STRUCT%%\nfn rgb2hsv(c : vec3<f32>) -> vec3<f32>\n{\nlet K = vec4<f32>(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);\nlet p = select(vec4<f32>(c.bg, K.wz), vec4<f32>(c.gb, K.xy), c.b < c.g);\nlet q = select(vec4<f32>(p.xyw, c.r), vec4<f32>(c.r, p.yzx), p.x < c.r);\nlet d = q.x - min(q.w, q.y);\nlet e = 1.0e-10;\nreturn vec3<f32>(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);\n}\nfn hsv2rgb(c : vec3<f32>) -> vec3<f32>\n{\nlet K = vec4<f32>(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);\nlet p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);\nreturn c.z * mix(K.xxx, clamp(p - K.xxx, vec3<f32>(0.0), vec3<f32>(1.0)), c.y);\n}\n@fragment\nfn main(input : FragmentInput) -> FragmentOutput\n{\nvar angleRad : f32 = shaderParams.uAngle * 3.14159265 / 180.0;\nvar offset : vec2<f32> = shaderParams.uDistance * 0.001 * vec2<f32>(cos(angleRad), sin(angleRad));\nvar shadow : vec4<f32> = vec4<f32>(0.0);\nfor (var i : i32 = -4; i <= 4; i = i + 1)\n{\nfor (var j : i32 = -4; j <= 4; j = j + 1)\n{\nlet sampledCoord : vec2<f32> = input.fragUV + offset + vec2<f32>(f32(i), f32(j)) * (shaderParams.uBlurRadius * 0.01) * 0.001;\nshadow = shadow + textureSample(textureFront, samplerFront, sampledCoord);\n}\n}\nshadow = shadow / 81.0;\nshadow.a = shadow.a * shaderParams.uOpacity;\nshadow = vec4<f32>(1.0, 0.0, 0.0, shadow.a);\nvar shadowHSV : vec3<f32> = rgb2hsv(shadow.rgb);\nshadowHSV.x = fract(shadowHSV.x + shaderParams.uHue / 360.0);\nshadowHSV.y = shaderParams.uSaturation;\nshadowHSV.z = shaderParams.uBrightness;\nshadow = vec4<f32>(hsv2rgb(shadowHSV), shadow.a);\nlet col : vec4<f32> = textureSample(textureFront, samplerFront, input.fragUV);\nlet shadowColor : vec4<f32> = mix(col, shadow, shadow.a);\nvar output : FragmentOutput;\noutput.color = mix(shadowColor, col, col.a);\nreturn output;\n}",
